import os
import logging
from datetime import datetime, timedelta

# Set up logging
logging.basicConfig(filename='home_directory_cleaner.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def is_essential_file(filename):
    """Check if a file is an essential system file."""
    essential_files = ['.bashrc', '.bash_history', '.gitignore', '.gitconfig', '.bash_profile', '.zshrc', '.profile']
    return filename in essential_files

def is_old_file(filename, days):
    """Check if a file is older than a specified number of days."""
    return datetime.now() - datetime.fromtimestamp(os.path.getctime(filename)) > timedelta(days=days)

def delete_file(filename):
    """Safely delete a file."""
    try:
        os.remove(filename)
        logging.info(f"Deleted file: {filename}")
    except OSError as e:
        logging.error(f"Failed to delete file: {filename}. Error: {e}")

